import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Button,
  Input,
  StatusBadge,
  Pagination,
  CatalogListShell,
  useCatalogTableBusy,
  addToast,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { FixedAssetDto } from '../../../services/tscd/models';
import { formatDateLocal, formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-tscd-list';
const PAGE_SIZE = 20;

const TscdListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<FixedAssetDto[]>([]);
  const [loading, setLoading] = useState(false);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const load = useCallback(() => {
    setLoading(true);
    tscdService.getAssets({ search: search.trim() || undefined, page, pageSize: PAGE_SIZE })
      .then(setItems)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải TSCĐ'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [dispatch, search, page]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
    });
  };

  const hasNext = items.length === PAGE_SIZE;
  const totalPages = hasNext ? page + 1 : page;

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}><i className="fas fa-building" /> Tài sản cố định</h1>
        </div>
        <div className={erp.headerActions}>
          <Button variant="primary" onClick={() => navigate('/tscd/them')} data-testid={`${TEST_ID}-create`}>
            <i className="fas fa-plus" /> Thêm mới
          </Button>
        </div>
      </div>

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách TSCĐ"
        showTableLoading={showTableLoading}
        filters={
          <>
            <div className={erp.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên TSCĐ..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={load} />
          </>
        }
        footer={
          (page > 1 || hasNext) ? (
            <div className={erp.paginationRow}>
              <Pagination
                currentPage={page}
                totalPages={totalPages}
                totalCount={hasNext ? page * PAGE_SIZE + 1 : (page - 1) * PAGE_SIZE + items.length}
                pageSize={PAGE_SIZE}
                onPageChange={setPage}
              />
            </div>
          ) : undefined
        }
      >
        {items.length === 0 ? (
          <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>Không có dữ liệu</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table} data-testid={`${TEST_ID}-table`}>
              <thead>
                <tr>
                  <th>Mã TS</th>
                  <th>Tên</th>
                  <th>Ngày mua</th>
                  <th className={erp.colRight}>Nguyên giá</th>
                  <th className={erp.colRight}>GT còn lại</th>
                  <th>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                    <td>
                      <button type="button" className={erp.codeLink} onClick={() => navigate(`/tscd/${r.id}`)}>
                        <code>{r.code}</code>
                      </button>
                    </td>
                    <td>{r.name}</td>
                    <td>{formatDateLocal(r.acquiredDate)}</td>
                    <td className={erp.colRight}>{formatVnd(r.originalCost)}</td>
                    <td className={erp.colRight}>{formatVnd(r.bookValue)}</td>
                    <td><StatusBadge status={r.status} /></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </CatalogListShell>
    </div>
  );
};

export default TscdListPage;
